{
  "domain_analysis": {
    "business_context": "A global logistics platform adding real-time driver earnings transparency across three jurisdictions with fundamentally different labor classifications, legal requirements, and approval processes. This is not a single feature — it is three distinct compliance regimes unified under one product surface.",
    "bounded_context": "Driver Compensation & Earnings Visibility",
    "ubiquitous_language": [
      { "term": "Base Pay", "definition": "The fixed compensation component for accepting and completing a delivery, before any bonuses, tips, or deductions. For employees (CA), this must meet or exceed minimum wage guarantees. For contractors (Indonesia), this is the agreed platform rate." },
      { "term": "Per-Delivery Bonus", "definition": "Variable compensation awarded per completed delivery, often based on distance, time, demand surge, or performance tier. Subject to different tax treatment depending on worker classification." },
      { "term": "Tip", "definition": "Voluntary gratuity from the customer to the driver. Must always be shown separately from platform-originated pay. In California, tips cannot offset minimum wage obligations." },
      { "term": "Deduction", "definition": "Any amount subtracted from gross earnings: equipment fees, insurance contributions, cash-on-delivery reconciliation shortfalls, tax withholdings, or platform fees. The legality and disclosure requirements for deductions vary sharply by jurisdiction." },
      { "term": "Gross Earnings", "definition": "Sum of Base Pay + Per-Delivery Bonus + Tips before any deductions are applied." },
      { "term": "Net Earnings", "definition": "Gross Earnings minus all Deductions. The amount the driver actually receives." },
      { "term": "Earnings Breakdown", "definition": "The itemized, real-time view showing each compensation component and deduction as a separate, labeled line item." },
      { "term": "Worker Classification", "definition": "The legal status of the driver — employee or independent contractor — which determines minimum wage obligations, deduction rules, tax withholding, and transparency requirements." },
      { "term": "Works Council (Betriebsrat)", "definition": "German employee representative body with legal co-determination rights. Must formally approve changes to compensation display systems before they go live in Germany under the Betriebsverfassungsgesetz (Works Constitution Act)." },
      { "term": "AB5 Classification", "definition": "California Assembly Bill 5 — presumes workers are employees unless the hiring entity proves the ABC test. Drivers classified as employees under AB5 have minimum wage, overtime, and pay transparency rights." },
      { "term": "Pay Period", "definition": "The time window over which earnings are accumulated before settlement. Relevant for real-time display accuracy — the breakdown must reflect the current pay period's running totals." }
    ]
  },

  "business_rules": [
    {
      "id": "BR-1",
      "rule": "Every earnings breakdown must itemize Base Pay, Per-Delivery Bonus, Tips, and Deductions as separate, labeled line items. No component may be aggregated into or hidden within another.",
      "invariant": true,
      "invariant_justification": "Combining components (e.g., folding tips into base pay) would misrepresent compensation structure. This corrupts the data integrity of the earnings record and violates the fundamental purpose of the feature.",
      "testable_assertion": "For any completed delivery, the earnings breakdown contains exactly four distinct labeled categories, and Gross Earnings = Base Pay + Per-Delivery Bonus + Tips, and Net Earnings = Gross Earnings - Deductions."
    },
    {
      "id": "BR-2",
      "rule": "Tips must never be counted toward base pay or used to offset minimum wage obligations in jurisdictions where drivers are classified as employees.",
      "invariant": true,
      "invariant_justification": "Under California law (and federal FLSA), using tips to meet minimum wage floors is illegal for employees. Violating this is a wage theft condition — the system state would be legally corrupt.",
      "testable_assertion": "In California, when calculating whether minimum wage is met, the sum used for comparison is Base Pay + Per-Delivery Bonus only; Tips are excluded from the minimum wage calculation."
    },
    {
      "id": "BR-3",
      "rule": "In California, earnings breakdown display is mandatory, not optional. Drivers cannot be shown a simplified or summary view that omits any component.",
      "invariant": true,
      "invariant_justification": "California wage transparency law requires itemized wage statements for employees. Offering a non-itemized view would put the platform in legal non-compliance regardless of driver preference.",
      "testable_assertion": "For drivers in the California jurisdiction, no UI path exists that displays earnings without full itemization of all four components."
    },
    {
      "id": "BR-4",
      "rule": "In Germany, the earnings transparency feature must not go live until formal Works Council (Betriebsrat) approval is obtained and recorded in the system.",
      "invariant": true,
      "invariant_justification": "Deploying compensation display changes without Betriebsrat approval violates the Works Constitution Act (BetrVG §87). This is a hard legal gate — bypassing it exposes the company to injunctions and nullification of the rollout.",
      "testable_assertion": "The Germany jurisdiction has a feature gate that requires a recorded Betriebsrat approval event before the earnings breakdown is visible to any German driver."
    },
    {
      "id": "BR-5",
      "rule": "Each deduction must be individually itemized with a labeled reason. A single aggregated 'Deductions' line is insufficient.",
      "invariant": true,
      "invariant_justification": "An opaque lump-sum deduction defeats transparency and, in California, violates itemized wage statement requirements. The driver cannot verify correctness of a deduction they cannot identify.",
      "testable_assertion": "The Deductions section of any earnings breakdown contains zero or more individually labeled deduction line items, each with a reason code and amount. No single 'total deductions' entry exists without sub-items."
    },
    {
      "id": "BR-6",
      "rule": "The earnings breakdown must reflect data no older than the platform's defined real-time threshold (e.g., within minutes of delivery completion), not batch-processed at end of day or pay period.",
      "invariant": false,
      "invariant_justification": "The exact latency threshold (seconds vs. minutes) is a product policy decision, not a data integrity constraint. A VP could adjust the freshness SLA based on infrastructure costs.",
      "testable_assertion": "After a delivery is marked complete, the earnings breakdown for that delivery appears in the driver's view within the configured real-time threshold."
    },
    {
      "id": "BR-7",
      "rule": "In Indonesia, the platform may offer the earnings breakdown as a value-add feature but is not legally obligated to do so. The feature may be toggled on or off for this jurisdiction without legal consequence.",
      "invariant": false,
      "invariant_justification": "This is a business policy decision, not a legal mandate. The platform could choose to enable or disable transparency in Indonesia based on competitive strategy.",
      "testable_assertion": "The Indonesia jurisdiction has a configurable feature flag that can enable or disable the earnings breakdown without affecting other jurisdictions."
    },
    {
      "id": "BR-8",
      "rule": "Worker classification (employee vs. independent contractor) determines which compliance rules apply. The system must never apply employee-specific rules (minimum wage floors, mandatory itemization) to contractors, or vice versa.",
      "invariant": true,
      "invariant_justification": "Misapplying classification rules creates legal exposure in both directions — treating contractors as employees implies misclassification liability; treating employees as contractors is wage theft.",
      "testable_assertion": "Given a driver's jurisdiction and classification, only the compliance rules matching that classification are enforced in the earnings breakdown logic."
    },
    {
      "id": "BR-9",
      "rule": "Earnings data is personal compensation data. Access must be restricted to the individual driver and authorized platform personnel. One driver must never see another driver's earnings.",
      "invariant": true,
      "invariant_justification": "Leaking one driver's compensation to another is a data integrity and privacy violation (GDPR in Germany, CCPA in California). This is a system corruption condition.",
      "testable_assertion": "Any API request for earnings data returns only records belonging to the authenticated driver. No endpoint returns earnings for a driver_id different from the authenticated session."
    },
    {
      "id": "BR-10",
      "rule": "Currency must match the driver's operating jurisdiction. California earnings in USD, Germany in EUR, Indonesia in IDR. No implicit currency conversion in the display.",
      "invariant": true,
      "invariant_justification": "Displaying earnings in the wrong currency or silently converting creates a factually incorrect earnings record.",
      "testable_assertion": "The currency code on every earnings line item matches the configured currency for the driver's jurisdiction."
    }
  ],

  "acceptance_criteria": [
    {
      "id": "AC-1",
      "given": "A driver in California completes a delivery",
      "when": "They view their earnings breakdown",
      "then": "They see Base Pay, Per-Delivery Bonus, Tips, and individually itemized Deductions as separate labeled line items, displayed in USD, within the real-time threshold"
    },
    {
      "id": "AC-2",
      "given": "A driver in California whose Base Pay + Per-Delivery Bonus for the pay period is below minimum wage",
      "when": "The system calculates their earnings",
      "then": "A minimum wage adjustment is applied and displayed as a separate line item, and Tips are not included in the minimum wage calculation"
    },
    {
      "id": "AC-3",
      "given": "The Germany jurisdiction has NOT received Betriebsrat approval",
      "when": "A German driver attempts to access the earnings breakdown feature",
      "then": "The feature is not visible or accessible; the driver sees their existing compensation view unchanged"
    },
    {
      "id": "AC-4",
      "given": "The Germany jurisdiction has received and recorded Betriebsrat approval",
      "when": "A German driver views their earnings breakdown",
      "then": "They see the full itemized breakdown in EUR with all components labeled, compliant with German data protection requirements"
    },
    {
      "id": "AC-5",
      "given": "A driver in Indonesia with the feature flag enabled",
      "when": "They view their earnings breakdown",
      "then": "They see Base Pay, Per-Delivery Bonus, Tips, and Deductions in IDR, without employee-specific compliance rules applied"
    },
    {
      "id": "AC-6",
      "given": "A driver in Indonesia with the feature flag disabled",
      "when": "They navigate to the earnings section",
      "then": "The detailed breakdown is not shown; they see only the existing summary view"
    },
    {
      "id": "AC-7",
      "given": "An authenticated driver requests earnings data via API",
      "when": "The request includes a driver_id that does not match their authenticated session",
      "then": "The request is rejected with an authorization error and no data is returned"
    },
    {
      "id": "AC-8",
      "given": "A driver has deductions applied (e.g., equipment fee, insurance, cash reconciliation)",
      "when": "They view their earnings breakdown",
      "then": "Each deduction is shown as a separate line item with a human-readable reason label, not as a single aggregated total"
    },
    {
      "id": "AC-9",
      "given": "A delivery was completed 1 minute ago",
      "when": "The driver refreshes their earnings view",
      "then": "The earnings from that delivery are reflected in the breakdown within the configured real-time threshold"
    }
  ],

  "edge_cases": [
    {
      "scenario": "A driver relocates from Indonesia to California mid-pay-period",
      "expected_behavior": "Worker classification and compliance rules must update to reflect the new jurisdiction. Historical earnings in Indonesia remain under contractor rules; new earnings in California fall under employee rules. The transition point must be clearly demarcated — no retroactive reclassification of Indonesian earnings."
    },
    {
      "scenario": "A California driver completes a delivery but receives $0 in tips",
      "expected_behavior": "The Tips line item still appears in the breakdown showing $0.00. Omitting the line would violate the mandatory itemization rule."
    },
    {
      "scenario": "A deduction exceeds gross earnings, resulting in negative net pay for a delivery",
      "expected_behavior": "The breakdown must still display accurately showing the negative net. For California employees, this may trigger wage law violations — the system should flag this for compliance review rather than silently allowing it."
    },
    {
      "scenario": "Betriebsrat approval in Germany is granted, then later revoked",
      "expected_behavior": "The feature must be immediately gated again for all German drivers. The system must support approval revocation, not just initial approval. Historical data already viewed remains viewed, but the feature becomes inaccessible going forward."
    },
    {
      "scenario": "A surge bonus is applied — where does it appear in the breakdown?",
      "expected_behavior": "Surge pricing bonuses should be categorized under Per-Delivery Bonus with a 'surge' label, not as a separate unlabeled category. The four-category structure (Base Pay, Per-Delivery Bonus, Tips, Deductions) must remain stable; sub-labels within categories handle variants."
    },
    {
      "scenario": "A customer retracts a tip after the driver has already seen it in the real-time view",
      "expected_behavior": "The breakdown must update to reflect the retraction with a visible adjustment line item. The driver must not see their earnings silently decrease — the adjustment must be explicit and labeled (e.g., 'Tip adjustment — customer modification')."
    },
    {
      "scenario": "Multiple deliveries completed within seconds of each other",
      "expected_behavior": "Each delivery generates its own distinct earnings breakdown entry. Deliveries must never be merged or aggregated into a single line item even if temporally adjacent."
    },
    {
      "scenario": "Platform is offline or data pipeline is delayed beyond the real-time threshold",
      "expected_behavior": "The driver sees a clear 'data pending' indicator rather than stale or partial data. Showing outdated earnings as if they are current would be misleading."
    }
  ],

  "business_impact": {
    "financial": "Legal compliance costs are the dominant financial driver. Non-compliance with AB5 in California exposes the platform to class-action wage theft lawsuits (penalties of $100-$200 per pay period per employee for itemized wage statement violations under Labor Code §226). In Germany, deploying without Betriebsrat approval risks injunctions that could halt operations. Positive ROI comes from reduced driver churn — transparent pay increases driver trust and retention, reducing recruitment costs (typically $500-$2000 per driver).",
    "operational": "Three distinct compliance regimes require jurisdiction-aware feature gating, not a single global rollout. The Germany rollout is blocked on an external approval process with no guaranteed timeline. The platform must support per-jurisdiction feature lifecycle management. Real-time earnings calculation adds load to the compensation pipeline — the system must handle delivery-completion spikes without degradation.",
    "user": "Drivers gain clear visibility into how their pay is computed, reducing disputes and support tickets. In California, this is a legal right — not a perk. In Indonesia, this is a competitive differentiator for driver acquisition. The risk is that exposing deductions transparently may surface dissatisfaction with fees drivers previously didn't scrutinize.",
    "risk": "HIGH in California (legal mandate — failure is wage violation), HIGH in Germany (Betriebsrat bypass is illegal), LOW in Indonesia (no legal mandate). Cross-jurisdiction data privacy is a material risk: GDPR in Germany requires strict data handling, CCPA in California gives drivers data access rights. A single global implementation without jurisdiction isolation would compound these risks.",
    "stakeholders_affected": [
      { "group": "Drivers (California)", "impact": "Gain legally mandated wage transparency. Must receive itemized statements — this is a rights fulfillment, not a feature launch." },
      { "group": "Drivers (Germany)", "impact": "Feature blocked until Works Council approves. Risk of frustration if they learn other regions have it first. Communication strategy needed." },
      { "group": "Drivers (Indonesia)", "impact": "Gain optional transparency feature that may improve trust and retention. No legal obligation but competitive advantage." },
      { "group": "Works Council (Germany)", "impact": "Must be engaged as a decision-making stakeholder, not merely informed. They have legal veto power over this feature in Germany." },
      { "group": "Legal & Compliance Team", "impact": "Must validate jurisdiction-specific rules before each regional launch. Ongoing obligation to update rules as labor law evolves (AB5 amendments, EU directives)." },
      { "group": "Finance / Payroll", "impact": "Must ensure earnings calculation engine produces data granular enough for the breakdown. Any rounding or aggregation in the backend will surface as visible errors in the driver-facing view." },
      { "group": "Customer Support", "impact": "Will see increased ticket volume during rollout as drivers question deductions they can now see. Must be trained on breakdown components." },
      { "group": "Product / Engineering", "impact": "Must build jurisdiction-aware feature gating, real-time calculation pipelines, and privacy-compliant data access controls. This is not a single feature — it is three compliance-scoped feature variants." }
    ]
  },

  "confidence": {
    "level": 52,
    "reasoning": "The spec is a single sentence that does not acknowledge the profound legal and jurisdictional complexity it implies. Three jurisdictions with three different worker classifications, three different legal regimes, and one jurisdiction requiring external third-party approval before deployment — none of this is addressed in the spec. Key ambiguities remain: what constitutes 'real-time,' whether the German Betriebsrat has been engaged, what deduction types exist, and how the feature interacts with existing payroll systems. The legal/regulatory nature of California and Germany requirements further caps confidence since I am not providing legal counsel.",
    "high_confidence_areas": [
      "Tips must not offset minimum wage for California employees — this is settled law",
      "Betriebsrat approval is a hard legal prerequisite in Germany — not optional",
      "Earnings components must be itemized separately — this is the explicit purpose of the feature",
      "Worker classification determines applicable rules — misapplication creates legal exposure in both directions"
    ],
    "low_confidence_areas": [
      "Exact deduction types and whether all are legally permissible in each jurisdiction — requires legal review",
      "Definition of 'real-time' — seconds, minutes, or per-refresh — not specified",
      "Whether German Works Council has been contacted or if this is greenfield — timeline implications are enormous",
      "Tax withholding display rules per jurisdiction — varies by classification and may require payroll system integration",
      "Whether Indonesia has any upcoming regulatory changes that would alter the optional nature of this feature"
    ],
    "assumptions": [
      "AB5 classification of California drivers as employees is settled and not under legal challenge",
      "The platform has an existing payroll/compensation engine capable of producing per-delivery granularity",
      "The German operation has an established Works Council — if not, different rules apply",
      "Tips are always customer-originated and never platform-subsidized",
      "The four-category breakdown (base, bonus, tips, deductions) is complete — no fifth category like 'expense reimbursements' exists"
    ]
  },

  "escalations": [
    {
      "type": "ambiguity",
      "description": "The spec says 'real time' but does not define an acceptable latency threshold. For a California employee, delayed wage visibility may have different legal implications than for an Indonesian contractor. Is 'real-time' sub-second, within minutes, or upon refresh?",
      "affected_stakeholders": ["Drivers (all jurisdictions)", "Engineering", "Legal"],
      "options": [
        "Define real-time as 'within 60 seconds of delivery completion' as a product SLA",
        "Define real-time as 'visible on next app refresh after delivery completion'",
        "Define different thresholds per jurisdiction based on legal requirements"
      ],
      "recommendation": "Define a single platform SLA (e.g., 60 seconds) that satisfies the strictest jurisdiction, then allow per-jurisdiction override if cost-prohibitive."
    },
    {
      "type": "ambiguity",
      "description": "The spec does not enumerate which deduction types exist or which are legally permissible per jurisdiction. California has strict rules on what can be deducted from employee wages (Labor Code §221-224). Displaying an illegal deduction transparently does not make it legal — it makes the violation visible.",
      "affected_stakeholders": ["Drivers (California)", "Legal & Compliance", "Finance"],
      "options": [
        "Conduct legal review of all deduction types per jurisdiction before implementation",
        "Display only deductions that have been pre-approved by legal for each jurisdiction",
        "Display all deductions but flag potentially impermissible ones for compliance review"
      ],
      "recommendation": "Legal must review and whitelist permissible deduction types per jurisdiction before the feature ships. Displaying illegal deductions is worse than not displaying deductions at all."
    },
    {
      "type": "missing_context",
      "description": "The status of Betriebsrat engagement in Germany is unknown. If the Works Council has not yet been contacted, the Germany rollout timeline could be months to years. If they have been engaged and are near approval, this is a near-term feature gate. This materially affects project scope and phasing.",
      "affected_stakeholders": ["Works Council (Germany)", "Drivers (Germany)", "Product", "Legal"],
      "options": [
        "Phase Germany out of initial launch entirely, ship California and Indonesia first",
        "Begin Betriebsrat engagement immediately in parallel with development",
        "Build the feature with a Germany gate and ship when approval is obtained"
      ],
      "recommendation": "Build with jurisdiction-aware gating from day one. Ship California (legally required) and Indonesia (optional) first. Begin Betriebsrat engagement immediately but do not block the overall project on it."
    },
    {
      "type": "ambiguity",
      "description": "The spec does not address tax withholding display. For California employees, income tax, Social Security, and state disability insurance are withheld. Should these appear as Deductions in the breakdown, or is 'Deductions' limited to platform-originated fees? This fundamentally changes what the driver sees.",
      "affected_stakeholders": ["Drivers (California)", "Finance / Payroll", "Legal"],
      "options": [
        "Show only platform-originated deductions; tax withholdings shown separately or in a payroll view",
        "Show all deductions including tax withholdings in the same breakdown",
        "Show platform deductions in real-time breakdown, tax withholdings in pay-period summary only"
      ],
      "recommendation": "Separate platform deductions from statutory withholdings. They have different sources of authority and different dispute paths. Mixing them in one view creates confusion about what the platform controls vs. what the government mandates."
    }
  ],

  "rejection_reasons": []
}

